e\";s:0:\"\";s:11:\"margin_left\";s:0:\"\";s:18:\"margin_left_medium\";s:0:\"\";s:22:\"margin_left_responsive\";s:0:\"\";s:4:\"type\";s:7:\"heading\";s:11:\"link-search\";s:0:\"\";s:21:\"as_values_link-search\";s:0:\"\";}}s:13:\"5c08accba960c\";O:8:\"stdClass\":5:{s:4:\"node\";s:13:\"5c08accba960c\";s:4:\"type\";s:6:\"module\";s:6:\"parent\";s:13:\"5c0209fd0bd50\";s:8:\"position\";i:3;s:8:\"settings\";O:8:\"stdClass\":36:{s:4:\"text\";s:1064:\"I used to poke fun at people who went to lots of WordCamps. I\'d joke about how they got any work done. Now, I am one of those people. At the time, I didn\'t realize how isolating remote work can be. Camps are an opportunity to get out from behind the computer screen and meet with the people we interact with daily face-to-face.\n\n<a href=\"https://2018.seattle.wordcamp.org/\">WordCamp Seattle</a> was an amazing camp thanks, no doubt, to the stellar organizing team, volunteers, speakers, and everyone that attended. I spent most of my time in the \"hallway track\" chit-chatting, but I did managed to squeeze in a few sessions.\n\nOne of my favorite talks was Chris Tiezel\'s session about data responsibility. The talk was about the responsibility developers have to consider unintended consequences of their work. One example was how the fitness tracking application, Strava, accidentally disclosed the location of a secret military base in the Middle East due to base personel using the software and that data subsequently being published on Strava\'s global heat map.\";s:5:\"color\";s:0:\"\";s:10:\"typography\";a:11:{s:11:\"font_family\";s:7:\"Default\";s:11:\"font_weight\";s:7:\"default\";s:9:\"font_size\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:2:\"px\";}s:11:\"line_height\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:0:\"\";}s:10:\"text_align\";s:0:\"\";s:14:\"letter_spacing\";a:1:{s:6:\"length\";s:0:\"\";}s:14:\"text_transform\";s:0:\"\";s:15:\"text_decoration\";s:0:\"\";s:10:\"font_style\";s:0:\"\";s:12:\"font_variant\";s:0: