e time back to writing and frontend design will be a lot more beneficial to my day-to-day work. Plus, I don\'t have to give up my obsession with time-lapse photography. :)\";s:5:\"color\";s:0:\"\";s:10:\"typography\";a:11:{s:11:\"font_family\";s:7:\"Default\";s:11:\"font_weight\";s:7:\"default\";s:9:\"font_size\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:2:\"px\";}s:11:\"line_height\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:0:\"\";}s:10:\"text_align\";s:0:\"\";s:14:\"letter_spacing\";a:1:{s:6:\"length\";s:0:\"\";}s:14:\"text_transform\";s:0:\"\";s:15:\"text_decoration\";s:0:\"\";s:10:\"font_style\";s:0:\"\";s:12:\"font_variant\";s:0:\"\";s:11:\"text_shadow\";a:4:{s:5:\"color\";s:0:\"\";s:10:\"horizontal\";s:0:\"\";s:8:\"vertical\";s:0:\"\";s:4:\"blur\";s:0:\"\";}}s:17:\"typography_medium\";a:9:{s:9:\"font_size\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:2:\"px\";}s:11:\"line_height\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:0:\"\";}s:10:\"text_align\";s:0:\"\";s:14:\"letter_spacing\";a:1:{s:6:\"length\";s:0:\"\";}s:14:\"text_transform\";s:0:\"\";s:15:\"text_decoration\";s:0:\"\";s:10:\"font_style\";s:0:\"\";s:12:\"font_variant\";s:0:\"\";s:11:\"text_shadow\";a:4:{s:5:\"color\";s:0:\"\";s:10:\"horizontal\";s:0:\"\";s:8:\"vertical\";s:0:\"\";s:4:\"blur\";s:0:\"\";}}s:21:\"typography_responsive\";a:9:{s:9:\"font_size\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:2:\"px\";}s:11:\"line_height\";a:2:{s:6:\"length\";s:0:\"\";s:4:\"unit\";s:0:\"\";}s:10:\"text_align\";s:0:\"\";s:14:\"letter_spacing\";a:1:{s:6:\"length\";s:0:\"\";}s:14:\"text_transform\";s:0:\"\";s:15:\"text_decoration\";s:0:\"\";s:10:\"font_style\";s:0:\"\";s:12:\"font_variant\";s:0:\"\";s:11:\"text_shadow\";a:4:{s:5:\"color\";s:0:\"\";s:10:\"horizontal\";s:0:\"\";s:8:\"vertical\";s:0:\"\";s:4:\"blur\";s:0:\"\";}}s:18:\"responsive_display\";s:0:\"\";s:18:\"visibility_display\";s:0:\"\";s:26:\"visibility_user_capability\";s:0:\"\";s:9:\"animation\";a:3:{s:5:\"style\";s:0:\"\";s:5:\"delay\";s:1:\"0