s:23:\"padding_responsive_unit\";s:2:\"px\";s:13:\"padding_right\";s:0:\"\";s:20:\"padding_right_medium\";s:0:\"\";s:24:\"padding_right_responsive\";s:0:\"\";s:14:\"padding_bottom\";s:0:\"\";s:21:\"padding_bottom_medium\";s:0:\"\";s:25:\"padding_bottom_responsive\";s:0:\"\";s:12:\"padding_left\";s:0:\"\";s:19:\"padding_left_medium\";s:0:\"\";s:23:\"padding_left_responsive\";s:0:\"\";}}s:13:\"5c363697ed704\";O:8:\"stdClass\":5:{s:4:\"node\";s:13:\"5c363697ed704\";s:4:\"type\";s:12:\"column-group\";s:6:\"parent\";s:13:\"5c363697ec9c7\";s:8:\"position\";i:0;s:8:\"settings\";s:0:\"\";}s:13:\"5c363697ed95a\";O:8:\"stdClass\":5:{s:4:\"node\";s:13:\"5c363697ed95a\";s:4:\"type\";s:6:\"column\";s:6:\"parent\";s:13:\"5c363697ed704\";s:8:\"position\";i:0;s:8:\"settings\";O:8:\"stdClass\":1:{s:4:\"size\";i:100;}}s:13:\"5c363697efa22\";O:8:\"stdClass\":5:{s:4:\"node\";s:13:\"5c363697efa22\";s:4:\"type\";s:6:\"module\";s:6:\"parent\";s:13:\"5c363697ed95a\";s:8:\"position\";i:0;s:8:\"settings\";O:8:\"stdClass\":28:{s:4:\"text\";s:1483:\"Hi! My name is Robby. Welcome to my blog.\r\n\r\nI am former freelance web developer &amp; designer turned marketer/entrepreneur. I am one of the co-founders of Beaver Builder, a <a href=\"https://www.wpbeaverbuilder.com\">website builder for WordPress</a>.\r\n<h2>Lets Connect</h2>\r\nI go through spurts of activity on social media and I love connecting with people.\r\n\r\nFind me on <a href=\"https://www.facebook.com/mybbor\">Facebook</a>, <a href=\"https://twitter.com/robbymccullough\">Twitter</a>, or <a href=\"https://www.instagram.com/robbymccullough/\">Instagram</a>.\r\n<h2>About my Blog</h2>\r\nOne of the reasons I decided to start a blog was to share some of the stories and lessons I\'ve learned in starting a company. I\'ve been inspired by the transparency of many great companies in our space and, in a way, I see this as a chance to give back—to share some knowledge.\r\n\r\nHere are a few of the things I am hoping to write about:\r\n<ul>\r\n 	<li>Music / Concerts</li>\r\n 	<li>Food / Cooking</li>\r\n 	<li>Coffee</li>\r\n 	<li>Traveling</li>\r\n 	<li>Business</li>\r\n 	<li>Marketing</li>\r\n 	<li>Productivity</li>\r\n</ul>\r\n<h2>Tools and Software</h2>\r\n<ul>\r\n 	<li><a href=\"https://wordpress.org/\" target=\"_blank\" rel=\"noopener\">WordPress</a></li>\r\n 	<li><a href=\"https://www.wpbeaverbuilder.com\" target=\"_blank\" rel=\"noopener\">Beaver Builder</a> (of course)</li>\r\n 	<li><a href=\"http://localhost/robbymccullough//go/godaddy-manged-wordpress\">GoDaddy Managed WordPress Hosting</a></li>\r\n</ul>\r\n&nbsp;\";s:5:\"color\";s:0:\"\";s:10:\"typography\";s:0:\"\";s:17:\"typography_medium\";s:0:\"\";s:21:\"typography_responsive\";s:0:\"\";s:18:\"responsive_display\";s:0:\"\";s:18:\"visibility_display\";s:0:\"\";s:26:\"visibility_user_capability\";s:0:\"\";s:9:\"animation\";s:0:\"\";s:17:\"container_element\";s:3:\"div\";s:2:\"id\";s:0:\"\";s:5:\"class\";s:0:\"\";s:10:\"margin_top\";s:0:\"\";s:11:\"margin_unit\";s:2:\"px\";s:17:\"margin_top_medium\";s:0:\"\";s:18:\"margin_medium_unit\";s:2:\"px\";s:21:\"margin_top_responsive\";s:0:\"\";s:22:\"margin_responsive_unit\";s:2:\"px\";s:12:\"margin_right\";s:0:\"\";s:19:\"margin_right_medium\";s:0:\"\";s:23:\"margin_right_responsive\";s:0:\"\";s:13:\"margin_bottom\";s:0:\"\";s:20:\"margin_bottom_medium\";s:0:\"\";s:24:\"margin_bottom_responsive\";s:0:\"\";s:11:\"margin_left\";s:0:\"\";s:18:\"margin_left_medium\";s:0:\"\";s:22:\"margin_left_responsive\";s:0:\"\";s:4:\"type\";s:9:\"rich-text\";}}}'),(713,12,'saved_flag','1'),(714,12,'_prlipro-post-options','a:3:{s:14:\"requested_slug\";s:0:\"\";s:19:\"hide_social_buttons\";i:0;s:20:\"disable_replacements\";i:0;}'),(715,12,'_fl_builder_draft_settings','O:8:\"stdClass\":2:{s:3:\"css\";s:0:\"\";s:2:\"js\";s:0:\"\";}'),(716,12,'_fl_builder_data','a:4:{s:13:\"5c363697ec9c7\";O:8:\"stdClass\":5:{s:4:\"node\";s:13:\"5c363697ec9c7\";s:4:\"type\";s:3:\"row\";s:6:\"parent\";N;s:8:\"position\";i:0;s:8:\"settings\